import { PriorityQueue } from 'typescript-collections';

function solve(n, edges) {
    const graph = new Map();
    for (const [u, v, w] of edges) {
        if (!graph.has(u)) {
            graph.set(u, []);
        }
        graph.get(u).push([v, w]);
    }

    const dist = new Array(n).fill(0).map(() => new Array(2).fill Infinity);
    dist[0][0] = 0;

    const pq = new PriorityQueue((a, b) => a[0] - b[0]);
    pq.enqueue([0, 0, false]);

    while (!pq.isEmpty()) {
        const [cost, node, hasSwitch] = pq.dequeue();
        if (node === n - 1) {
            return cost;
        }
        if (cost > dist[node][hasSwitch]) {
            continue;
        }

        // Traverse original edges
        for (const [neighbor, weight] of graph.get(node) || []) {
            const newCost = cost + weight;
            if (newCost < dist[neighbor][hasSwitch]) {
                dist[neighbor][hasSwitch] = newCost;
                pq.enqueue([newCost, neighbor, hasSwitch]);
            }
        }

        // If switch hasn't been used, consider flipping the edge
        if (!hasSwitch) {
            for (const [neighbor, weight] of graph.get(node) || []) {
                const newCost = cost + 2 * weight;
                if (newCost < dist[neighbor][true]) {
                    dist[neighbor][true] = newCost;
                    pq.enqueue([newCost, neighbor, true]);
                }
            }
        }
    }

    return -1;
}
